// Function to generate a random date within the last 3 months
function generateRandomDate() {
    // Get the current date
    var currentDate = new Date();

    // Calculate the date 3 months ago
    var threeMonthsAgo = new Date();
    threeMonthsAgo.setMonth(currentDate.getMonth() - 3);

    // Generate a random timestamp between now and three months ago
    var randomTimestamp = new Date(
        threeMonthsAgo.getTime() + Math.random() * (currentDate.getTime() - threeMonthsAgo.getTime())
    );

    // Format the date as "YYYY-MM-DD HH:mm:ss"
    var year = randomTimestamp.getFullYear();
    var month = ('0' + (randomTimestamp.getMonth() + 1)).slice(-2); // Month is zero-indexed
    var day = ('0' + randomTimestamp.getDate()).slice(-2);
    var hours = ('0' + randomTimestamp.getHours()).slice(-2);
    var minutes = ('0' + randomTimestamp.getMinutes()).slice(-2);
    var seconds = ('0' + randomTimestamp.getSeconds()).slice(-2);

    // Combine to get the formatted date string
    var formattedDate = year + '-' + month + '-' + day + ' ' + hours + ':' + minutes + ':' + seconds;

    return formattedDate;
}

// Example usage
var randomDate;

var getCostRecords = new GlideRecord('u_ev_costs');
getCostRecords.addActiveQuery();
getCostRecords.query();

while (getCostRecords.next()) {
    randomDate = generateRandomDate();
    getCostRecords.u_operation_date = randomDate;
    getCostRecords.update();
}
